assert_11_load_weight_vector: assert property (p_load_weight_vector)
else $error("Assertion failed: load_weight_vector");

cover_11_load_weight_vector: cover property (p_load_weight_vector);

// Behavior: store_activation
// Given: Activation vector and address
// When: Storing layer output
// Then: Writes vector to activation buffer
property p_store_activation;
@(posedge clk) disable iff (!rst_n)
1'b1 |-> 1'b1;
    endproperty

assert_12_store_activation: assert property (p_store_activation)
else $error("Assertion failed: store_activation");

cover_12_store_activation: cover property (p_store_activation);

// Behavior: fsm_idle
// Given: Core in IDLE state
// When: Start signal asserted
// Then: Transition to LOAD_WEIGHTS
property p_fsm_idle;
@(posedge clk) disable iff (!rst_n)
(state == IDLE) |-> 1'b1;
    endproperty

assert_13_fsm_idle: assert property (p_fsm_idle)
else $error("Assertion failed: fsm_idle");

cover_13_fsm_idle: cover property (p_fsm_idle);

// Behavior: fsm_compute
// Given: Weights and activations loaded
// When: In COMPUTE_MAC state
// Then: Execute MAC operations, transition to APPLY_ACTIVATION
property p_fsm_compute;
@(posedge clk) disable iff (!rst_n)
1'b1 |-> 1'b1;
    endproperty

assert_14_fsm_compute: assert property (p_fsm_compute)
else $error("Assertion failed: fsm_compute");

cover_14_fsm_compute: cover property (p_fsm_compute);

// Behavior: fsm_done
// Given: All layers processed
// When: Final activation stored
// Then: Assert done signal, return to IDLE
property p_fsm_done;
@(posedge clk) disable iff (!rst_n)
(state == PROCESS) |-> 1'b1;
    endproperty

assert_15_fsm_done: assert property (p_fsm_done)
else $error("Assertion failed: fsm_done");

cover_15_fsm_done: cover property (p_fsm_done);

// Behavior: count_cycles
// Given: Core is busy
// When: Each clock cycle
// Then: Increment cycle counter
property p_count_cycles;
@(posedge clk) disable iff (!rst_n)
1'b1 |-> (count == $past(count) + 1);
    endproperty

assert_16_count_cycles: assert property (p_count_cycles)
else $error("Assertion failed: count_cycles");

cover_16_count_cycles: cover property (p_count_cycles);

// Behavior: count_mac_ops
// Given: MAC operation completes
// When: Valid result produced
// Then: Increment MAC counter
property p_count_mac_ops;
@(posedge clk) disable iff (!rst_n)
1'b1 |-> (count == $past(count) + 1);
    endproperty

assert_17_count_mac_ops: assert property (p_count_mac_ops)
else $error("Assertion failed: count_mac_ops");

cover_17_count_mac_ops: cover property (p_count_mac_ops);

    // ═══════════════════════════════════════════════════════════════════════════════
    // SACRED IDENTITY ASSERTION
    // ═══════════════════════════════════════════════════════════════════════════════

    // φ² + 1/φ² = 3 (verified at compile time)
    localparam real PHI = 1.6180339887498948482;
    localparam real GOLDEN_IDENTITY = PHI * PHI + 1.0 / (PHI * PHI);

    // Compile-time check (synthesis will optimize this)
    initial begin
        if (GOLDEN_IDENTITY < 2.99 || GOLDEN_IDENTITY > 3.01)
            $fatal(1, "Golden Identity violated: φ² + 1/φ² != 3");
    end

endmodule
